const src = $input.first().json;
const b = src.body && typeof src.body === 'object' ? src.body : src;
const projectId = String(b.project_id || src.project_id || '').trim();
const docSummary = String(b.document_summary || src.document_summary || 'No document summary provided.').trim();
return [{ json: { project_id: projectId, document_summary: docSummary } }];

const items = $input.all();
const projectId = $('Normalize Input').first().json.project_id;
function collectStrings(v, out) { if (typeof v === 'string') { out.push(v); return; } if (Array.isArray(v)) { v.forEach(x => collectStrings(x, out)); return; } if (v && typeof v === 'object') { ['text', 'merged', 'output', 'completion', 'response', 'content', 'message'].forEach(k => { if (v[k] !== undefined) collectStrings(v[k], out); }); } }
function tryParse(s) { if (typeof s !== 'string') return null; let t = s.trim(); t = t.replace(/```json/gi, '').replace(/```/g, '').trim(); const first = t.indexOf('{'); const last = t.lastIndexOf('}'); if (first === -1 || last === -1 || last <= first) return null; t = t.slice(first, last + 1); try { const p = JSON.parse(t); return p && typeof p === 'object' && !Array.isArray(p) ? p : null; } catch (e) { return null; } }
let parsed = null;
let rawAll = '';
for (const it of items) { const out = []; collectStrings(it.json, out); rawAll = rawAll + out.join('\n'); for (const s of out) { parsed = tryParse(s); if (parsed) break; } if (parsed) break; }
if (!parsed) { parsed = tryParse(rawAll); }
if (!parsed) { return [{ json: { parse_ok: false, project_id: projectId, error_message: 'Could not parse strict JSON from the AI response', raw_snippet: rawAll.slice(0, 500) } }]; }
const rec = Array.isArray(parsed.recommendations) ? parsed.recommendations : (parsed.recommendations ? [String(parsed.recommendations)] : []);
return [{ json: { parse_ok: true, project_id: projectId, executive_summary: String(parsed.executive_summary || ''), timeline: parsed.timeline && typeof parsed.timeline === 'object' ? parsed.timeline : {}, risk_analysis: parsed.risk_analysis && typeof parsed.risk_analysis === 'object' ? parsed.risk_analysis : {}, cost_breakdown: parsed.cost_breakdown && typeof parsed.cost_breakdown === 'object' ? parsed.cost_breakdown : {}, recommendations: rec, detailed_report: String(parsed.detailed_report || ''), status: 'Generated', generated_by_ai: true } }];
